        SELECT 
          COALESCE(k.user_id, l.responsavel_id, 'admin@dm.com'),
          COALESCE(MAX(l.nome), 'Desconhecido') as nome,
          MAX(l.email) as email,
          l.telefone,
          MAX(l.responsavel_id) as responsavel_id
